import{_ as a,o as t,c as i,ak as l,bt as r,bu as p,bv as s,bw as o,bx as c,by as _,bz as n,bA as m,bB as T,bC as b}from"./chunks/framework.Bj6Oe1e0.js";const u=JSON.parse('{"title":"Keil RTE 工具配置项目","description":"","frontmatter":{},"headers":[],"relativePath":"STM32 系列/Keil RTE 工具.md","filePath":"STM32 系列/Keil RTE 工具.md"}'),d={name:"STM32 系列/Keil RTE 工具.md"};function k(h,e,K,P,S,x){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="keil-rte-工具配置项目" tabindex="-1">Keil RTE 工具配置项目 <a class="header-anchor" href="#keil-rte-工具配置项目" aria-label="Permalink to “Keil RTE 工具配置项目”">​</a></h1><p>Keil RTE (Run-time Environment) 是 MDK 工具链的核心组件之一。其是一种基于 CMSIS-Pack 标准的管理机制，允许使用库管理器的方式引入新的软件组件。开发者可以通过这种方式引入众多软件组件（比如 RTOS、FS、各驱动程序等），自动集成到工程中。</p><p>本文在 Nucleo_F411RE 开发板的基础上，介绍了如何利用 Keil RTE 工具集成 CubeMX HAL 库。</p><h2 id="项目配置" tabindex="-1">项目配置 <a class="header-anchor" href="#项目配置" aria-label="Permalink to “项目配置”">​</a></h2><p>打开 Keil，新建项目。此时，Keil 会自动打开 RTE 工具。手动打开的方式如下图所示。</p><p><img src="'+r+'" alt="alt text"></p><p>RTE 工具中列举了已经下载的软件组件。如下图所示。</p><p><img src="'+p+'" alt="alt text"></p><p>在下载 STM32F4XX_DFP 的过程中，Keil 自动安装了 Device 系列组件，即芯片厂商提供的设备相关软件组建。展开，即可找到 CubeMX 组件。勾选，并点击右侧的启动按钮。</p><p><img src="'+s+'" alt="alt text"></p><p>此时，Keil 会自动打开 CubeMX 软件，并新建 CubeMX 配置文件在项目文件夹中。进行 HAL 库配置并生成代码后，Keil 会在 Keil Project 配置文件的文件目录结构中添加对应生成 HAL 库头、源文件的位置，如图所示。</p><p><img src="'+o+'" alt="alt text"></p><blockquote><p>其中文件夹图标的表示由 Keil 构建的文件目录，绿色 “Pack” 图标的表示已经添加到该项目的软件组件。可以发现 Device 组件已经被添加到项目中。</p></blockquote><p>编译，发现没有报错，证明已经成功引入了 HAL 库组件。这些组件存放在项目根目录下。</p><h2 id="其他组件" tabindex="-1">其他组件 <a class="header-anchor" href="#其他组件" aria-label="Permalink to “其他组件”">​</a></h2><p>Keil 提供了一套完善的包管理器用于进行软件组件的安装。点击 <code>Pack Installer</code> 按钮，打开包安装器（管理器）。</p><blockquote><p>Pack Installer 会在每次打开时与线上库进行同步，所以会有暂时的卡顿。</p></blockquote><p><img src="'+c+'" alt="alt text"></p><p>左侧是按照供应商分类的设备/开发版目录，点击就可以在右侧显示适用于该平台的软件组件。</p><p>点击 STMicroelectronics 下属的 STM32F4 Series，可以看到右侧出现了平台特有（Device Specific）的 DFP 支持组件（即标准库），以及共有组件（Generic）。</p><p><img src="'+_+'" alt="alt text"></p><p>可以看到，支持该系列芯片的软件组件包括了：</p><ul><li>RTOS (ARM::CMSIS-FreeRTOS)</li><li>协议驱动（MDK-Packs::HTTP_Parser、MDK-Packs::PahoMQTT）</li><li>功能库（LVGL::lvgl、tensorflow::tensorflow-lite-micro）</li><li>设备驱动（MDK-Packs::QCA400x_WiFi_Driver）</li><li>...</li></ul><p>用户可以根据需求下载并集成到 Keil 中。</p><h2 id="开发辅助工具" tabindex="-1">开发辅助工具 <a class="header-anchor" href="#开发辅助工具" aria-label="Permalink to “开发辅助工具”">​</a></h2><p>Keil 在 RTE 组件的基础上提供了集成在软件内部的帮助文档。点击左栏下方的 Books 按钮。</p><p><img src="'+n+'" alt="alt text"></p><p>其会出现一系列的文档，分为 Device Specific 和 Generic 两部分，和 Pack Installer 中相对应。这是关于这些软件组建的文档。当在项目中引入了某个组件，其就会在 Books 页面引用这个组件的文档。双击即可查看，如图所示。</p><p><img src="'+m+'" alt="alt text"></p><p>当然，这部分时可以设置的。点击 Pack Installer 按钮左侧的 File Extensions, Books and Environment... 按钮，如下图所示。</p><p><img src="'+T+'" alt="alt text"></p><p>进入 Books 页面，就可以看到所有文档的索引。可以自行添加文档。</p><p><img src="'+b+'" alt="alt text"></p>',33)])])}const E=a(d,[["render",k]]);export{u as __pageData,E as default};
